def log_execution_time(func: Callable) -> Callable:
    """
    函数执行时间装饰器

    使用示例：
        @log_execution_time
        async def my_function():
            pass
    """
    @wraps(func)
    async def async_wrapper(*args, **kwargs):
        start = time.time()
        try:
            result = await func(*args, **kwargs)
            duration = (time.time() - start) * 1000
            logger.info(
                "function_executed",
                function=func.__name__,
